import{_ as t,o,c as a,ae as r}from"./chunks/framework.BGHOrOyn.js";const d=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/troubleshooting.md","filePath":"robotics/troubleshooting.md"}'),i={name:"robotics/troubleshooting.md"};function s(n,e,l,h,c,p){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>This page shares issues that users have run into and how they were resolved. Hopefully this will help to solves issues for others.</p><h2 id="vehicle-control" tabindex="-1">Vehicle Control <a href="#vehicle-control" id="vehicle-control"></a> <a class="header-anchor" href="#vehicle-control" aria-label="Permalink to &quot;Vehicle Control &lt;a href=&quot;#vehicle-control&quot; id=&quot;vehicle-control&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><strong>Vehicle has telemetry but does not respond to joystick</strong></p><p>Make sure you followed the instructions in Joystick/Gamepad Calibration and that the &quot;Enable joystick input&quot; checkbox is checked.</p><p><strong>Vehicle flips itself over</strong></p><p>Check that the motor directions are configured correctly. Also check that the motors are connected to the correct motor outputs on the flight controller, according to the supported frame diagrams.</p><p><strong>Vehicle turns or moves even when not controlled to do so.</strong></p><p>Please check RCx_TRIM parameters to make sure that all trims are set to 1500, with the exception of RC3_TRIM, which should be set to 1100.</p><p><strong>Motors spin as soon as the vehicle is armed.</strong></p><p>Make sure that the vehicle is in <em>Manual</em> mode.</p><p>The flight controller attempts to stabilize the vehicle&#39;s attitude so that it is perfectly level. If the vehicle&#39;s attitude is off from level, even a fraction of a degree, the flight controller will spin the motors in an attempt to correct the error. If the vehicle is sitting on land, the error will not change, and the flight controller will spin the motors faster and faster as it tries harder and harder to correct the error. Testing the vehicle on land should be done in MANUAL mode, which just passes pilot inputs to the motors with no stabilization.</p><h3 id="no-telemetry-waiting-for-vehicle-connection-no-autopilot-connection" tabindex="-1">No Telemetry / &quot;Waiting for Vehicle Connection&quot; (No Autopilot Connection) <a href="#no-telemetry--waiting-for-vehicle-connection-no-autopilot-connection" id="no-telemetry--waiting-for-vehicle-connection-no-autopilot-connection"></a> <a class="header-anchor" href="#no-telemetry-waiting-for-vehicle-connection-no-autopilot-connection" aria-label="Permalink to &quot;No Telemetry / &quot;Waiting for Vehicle Connection&quot; (No Autopilot Connection) &lt;a href=&quot;#no-telemetry--waiting-for-vehicle-connection-no-autopilot-connection&quot; id=&quot;no-telemetry--waiting-for-vehicle-connection-no-autopilot-connection&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><strong>Verify Network Configuration</strong></p><p>Verify that your network settings are correct. Verify your network configuration by entering the command <code>ipconfig</code> (Windows) or <code>ifconfig</code> (Mac/Linux) on the surface computer command line. The output should show that your Ethernet IP address is 192.168.2.1 and the subnet mask is 255.255.255.0.</p><p><em>Carefully double check that you have entered these numbers correctly</em>. The Ethernet IP address should be <em>exactly</em> <em><strong>192.168.2.1</strong></em> and the subnet mask should be <em>exactly</em> <em><strong>255.255.255.0</strong></em>.</p><p>You should be able to ping the companion computer from the surface computer. On the surface computer&#39;s command line enter:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ping </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.2.2</span></span></code></pre></div><p>If you do not get a ping response, then something is wrong with the network communication between the surface computer and the companion computer. You may have to adjust your firewall and/or antivirus settings to allow QGrouncControl access to the network.</p><p><strong>Firewall and Antivirus</strong></p><p>Antivirus and firewall software can block the incomming connection from the ROV. Make an exception/rule to allow <em>inbound and outbound</em> traffic on UDP ports 5600 and 14550, or turn off your antivirus and firewall software.</p><p><strong>Cabling</strong></p><p>Try replacing your Ethernet cable. Sometimes the wires inside a cable break, and the cable stops working.</p><p><strong>Reboot Computer</strong></p><p>If you are using Windows, sometimes the computer needs to be rebooted for network settings to take affect.</p><p><strong>Verify QGC Autoconnect settings</strong></p><p>Make sure that the QGroundControl is configured to automatically connect to UDP and USB links. Click on the &#39;Q&#39; icon in the upper left to view the Application Settings. Click on the &#39;General Settings&#39; tab. In the options for &#39;Autoconnect to:&#39;, make sure the UDP option is checked.</p><p><strong>Verify Autopilot USB Connection</strong></p><p>Check if the Autopilot is connected with following steps:</p><ol><li>Navigate to the system page in the Companion web interface</li><li>Check the list of detected serial devices for an entry that says <code>Pixhawk Autopilot</code></li><li>If you do not see an entry that says <code>Pixhawk Autopilot</code>, check the autopilot connection with the Companion computer. <ul><li>You can test the autopilot and the usb cable by connecting the autopilot directly to your surface computer and checking the connection with QGroundControl.</li><li>If you cannot connect to the autopilot: <ol><li>Try using a different usb cable. Make sure that the USB cable has data lines, some USB cables only provide power and will not allow communication. You can connect the Pixhawk to the surface computer directly with the USB cable to verify that the USB cable works.</li><li>Try connecting the autopilot to a different usb port</li><li>Try replacing the autopilot</li></ol></li></ul></li><li>If you see an entry in the detected serial devices list that says <code>Pixhawk Autopilot (bootloader)</code>, you must flash the autopilot with ArduSub firmware. Click the &#39;Restore Default Firmware&#39; button on the system page, and wait for the text on the bottom of the page to indicate that the process is complete.</li></ol><p>If you do not see the system web page, make sure the companion computer is powered on with a supply that is capable of delivering at least 2A. Check the activity lights on the Raspberry Pi Ethernet Jack. The lights should be on or blinking. If the lights are not on, make sure that you are using a network patch cable, not a crossover cable. Look closely at the color of the wires inside connectors on either end of the network cable, the order of the wires should be the same on both ends of the cable. If everything appears ok with the companion computer and the physical network connection, check your network settings (below).</p><p><strong>Check MAVProxy</strong></p><p>If your network is configured correctly, but you still have no telemetry, we need to make sure that MAVProxy is running on the companion computer and that the autopilot and MAVProxy are communicating.</p><p>To verify that MAVProxy is running, visit the system page in the companion web interface, and look for the <code>mavproxy</code> entry under the list of active services.</p><p>To verify that MAVProxy and the autopilot are communicating, log into the Companion computer via the web terminal, ssh, or PuTTY (user: pi, password: companion), and enter the command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>screen -r mavproxy</span></span></code></pre></div><p>If Mavproxy and the autopilot are working correctly, the output should contain something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>APM: ArduSub V3.4 (422c10cf)</span></span>
<span class="line"><span>APM: PX4: 96a4c296 NuttX: 580f5354</span></span>
<span class="line"><span>APM: Frame: ROV_VECTORED_FRAME</span></span>
<span class="line"><span>APM: PX4v2 0048003B 3135510C 35333436</span></span>
<span class="line"><span>Received 608 parameters</span></span>
<span class="line"><span>Saved 608 parameters to mav.parm</span></span></code></pre></div><p>To return to the command line and keep the mavproxy process running, hit control+a then type &#39;d&#39; (to detach).</p><p>If you still do not have telemetry after all of these steps, please reboot the surface computer and the companion computer, and try again. If it is still not working after rebooting, please leave a comment on discuss.bluerobotics.com with notes on your results of all of the above troubleshooting steps.</p><p><strong>Reset MavProxy Options</strong></p><p>Some updates require changes to the MavProxy options. To avoid overwriting user changes, those do not apply until you <strong>Restore Default Options</strong>. Navigate to MavProxy page and click <strong>Restore Default Options</strong>. This will erase the current options, revert to the default for the current companion version, and reset the MavProxy service.</p><h3 id="no-video" tabindex="-1">No Video <a href="#no-video" id="no-video"></a> <a class="header-anchor" href="#no-video" aria-label="Permalink to &quot;No Video &lt;a href=&quot;#no-video&quot; id=&quot;no-video&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If you do not have telemetry, please troubleshoot that first according to the above instructions.</p><p>Begin by verifying that your network settings are correct, your Ethernet IP address should be 192.168.2.1 and the subnet mask should be 255.255.255.0.</p><p>If you have telemetry, but no video, make sure the video settings are correct in QGroundControl. The video settings are found in the General tab of the Application Settings (Q icon) view. The video source should be set to UDP video, and the port should be 5600. These are the default settings. If you change these settings, you will need to close and re-launch QGroundControl.</p><p>If you are using Linux, you must install a few dependencies for the video to work:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apt install gstreamer1.0-x gstreamer1.0-libav gstreamer1.0-plugins-base gstreamer1.0-plugins-good gstreamer1.0-plugins-bad gstreamer1.0-plugins-ugly</span></span></code></pre></div><p>Verify that your camera is detected by seeing it listed under the detected video devices section on the Companion system webpage. If your camera is not detected, make sure that the camera supports H.264 video output, and make sure the cable is well-seated, or try another camera cable.</p><p>Verify that the video streaming service is active; it should be listed under the active services on the Companion system webpage.</p><p><strong>If you are using a Windows computer:</strong></p><ul><li>Disable/re-enable the network interface</li><li>Reboot</li><li>QGC installs three shortcuts: <em>QGC</em>, <em>QGC (GPU Safe Mode)</em>, and <em>QGC (GPU Compatibility Mode)</em>. Try launching QGC with each of these shortcuts</li></ul><h3 id="poor-video-streaming-performance" tabindex="-1">Poor video streaming performance <a href="#poor-video-streaming-performance" id="poor-video-streaming-performance"></a> <a class="header-anchor" href="#poor-video-streaming-performance" aria-label="Permalink to &quot;Poor video streaming performance &lt;a href=&quot;#poor-video-streaming-performance&quot; id=&quot;poor-video-streaming-performance&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The video stream should have about 200ms delay, just barely noticeable. There are many factors that could cause lag, low framerate, and pixelation/tearing in the video.</p><p>Here are some tips for troubleshooting poor video performance:</p><p><strong>In general:</strong></p><ul><li>Bandwidth - Test the bandwidth at <a href="http://192.168.2.2:2770/network" target="_blank" rel="noreferrer">192.168.2.2:2770/network</a>. The maximum theoretical bandwidth on a Raspberry Pi 3 is 100Mbps, if the bandwidth tests achieve greater than 70Mbps, it is a very good connection. Systems with bandwidths below 15Mbps should be diagnosed for issues.</li><li>Try another cable - Not all cables are created equal; some are really junk.</li><li>Update Software - Use the latest software to make sure you are getting the best performance.</li><li>Companion computer power supply - Most companion computers require a power supply capable of providing 5V at 2A. Smaller/weaker power supplies can severely affect performance of the companion computer.</li><li>Tether interface power supply - If you are using a tether interface board, make sure it has a solid power supply. Some laptop USB ports cannot provide enough power for the tether interface board to perform optimally. Try using a portable USB battery charger.</li><li>Tether interface connections - Make sure that all connections are well-seated and tight.</li><li>System resources - Open the system resource monitor and look at how much CPU and RAM your computer is using. Try closing other programs like anti-virus and screen recorders to make more system resources available to programs used to operate the vehicle.</li><li>Resolution - Modify the video stream Frame Size at <a href="http://192.168.2.2:2770/camera" target="_blank" rel="noreferrer">192.168.2.2:2770/camera</a>. Change it to a value equal to or less than the resolution of your display.</li></ul><p><strong>If you are using a Raspberry Pi camera:</strong></p><ul><li>Delete the &#39;--intra 1&#39; setting at <a href="http://192.168.2.2:2770/camera" target="_blank" rel="noreferrer">192.168.2.2:2770/camera</a> and restart the camera.</li><li>Update the companion computer software at <a href="http://192.168.2.2:2770/system" target="_blank" rel="noreferrer">192.168.2.2:2770/system</a>.</li></ul><p><strong>If you are using a Windows computer:</strong></p><ul><li>Upgrade to Windows 10!</li><li>Try these three suggestions by <a href="http://discuss.bluerobotics.com/t/video-delay-in-qgc/1335/5" target="_blank" rel="noreferrer">Bo Koppel</a>: <ol><li>When using original power supply that supply laptop (but not charge at the same time) there is something probably in BIOS that slow down graphic card to save energy. That makes processor do some of the graphics calculations. (And actually consume even more energy!) Solution: Go on battery or use a large powersupply (in our case 120W) How to quick check if this is the problem: pull out powersupply, if this is the case, latency disappear in two seconds.</li><li>Nvidia powerful graphic cards use an engine called PhysX for games etc. It seams QGC does not use that. Also QGC works default on motherboard graphic card, not on the more powerful Nvidia extension card. Solution: In Nvidias “control panel” select under “Programs” QGC so Nvidia forces QGC to use Nvidia card. Some graphic cards also needs tweeking in Nvidia 3D setup (same place as above line)</li><li>Real crazy in a few computers: Switch system fonts from 125% size to 100% (Right click desktop, “adjust screen” then “monitor” translated from Swedish OS) Check the 100% tickbox instead of 125% Log out and log in again, fixed….</li></ol></li></ul><h3 id="miscellaneous" tabindex="-1">Miscellaneous <a href="#miscellaneous" id="miscellaneous"></a> <a class="header-anchor" href="#miscellaneous" aria-label="Permalink to &quot;Miscellaneous &lt;a href=&quot;#miscellaneous&quot; id=&quot;miscellaneous&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="camera-does-not-tilt" tabindex="-1">Camera does not tilt <a href="#camera-does-not-tilt" id="camera-does-not-tilt"></a> <a class="header-anchor" href="#camera-does-not-tilt" aria-label="Permalink to &quot;Camera does not tilt &lt;a href=&quot;#camera-does-not-tilt&quot; id=&quot;camera-does-not-tilt&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The output servo rail on the Pixhawk requires a separate 5V power supply. The power module and USB power inputs on the Pixhawk will not power the servo rail. Make sure you have a 5V input on the servo rail via an ESC BEC or standalone BEC.</p><p>Check that input/output channels are configured for camera tilt.</p><p>Check that joystick buttons have been assigned to camera tilt functions.</p><h4 id="no-io-thread-heartbeat-message-constantly-appears" tabindex="-1">&quot;No io thread heartbeat&quot; message constantly appears. <a href="#no-io-thread-heartbeat-message-constantly-appears" id="no-io-thread-heartbeat-message-constantly-appears"></a> <a class="header-anchor" href="#no-io-thread-heartbeat-message-constantly-appears" aria-label="Permalink to &quot;&quot;No io thread heartbeat&quot; message constantly appears. &lt;a href=&quot;#no-io-thread-heartbeat-message-constantly-appears&quot; id=&quot;no-io-thread-heartbeat-message-constantly-appears&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>This message indicates that the APM io thread has stopped running. The most likely cause is a corrupted filesystem on the micro SD card. Remove the card from the pixhawk, and format it as FAT32. If the error persists, you will need to replace the SD card, or disable dataflash log files by setting the LOG_BACKEND_TYPE parameter to None (0).</p><h4 id="compass-heading-drifts-while-the-vehicle-is-stationary" tabindex="-1">Compass heading drifts while the vehicle is stationary <a href="#compass-heading-drifts-while-the-vehicle-is-stationary" id="compass-heading-drifts-while-the-vehicle-is-stationary"></a> <a class="header-anchor" href="#compass-heading-drifts-while-the-vehicle-is-stationary" aria-label="Permalink to &quot;Compass heading drifts while the vehicle is stationary &lt;a href=&quot;#compass-heading-drifts-while-the-vehicle-is-stationary&quot; id=&quot;compass-heading-drifts-while-the-vehicle-is-stationary&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The compass inside of the ROV is very sensitive and will be affected by large iron/steel structures, including rebar in concrete. You will get the best compass calibration outside, away from large structures and concrete. It is possible to calibrate inside, you may need to increase the value of the COMPASS_OFS_MAX parameter before you get a passing calibration. Note that the compass will always be affected by ferrous structures because they distort Earth&#39;s magnetic field, however the heading should remain stationary (maybe incorrect) while the vehicle is stationary in any case.</p><p>Perform these steps to recalibrate the compass:</p><ol><li>Power on the vehicle and wait 10 minutes to ensure the sensors are warmed up.</li><li>Make sure that the INS_GYR_CAL parameter value is set to &#39;Never&#39;.</li><li>Perform an accelerometer calibration.</li><li>Perform a compass calibration.</li><li>Reboot the vehicle. The compass should be still.</li></ol><h3 id="issue-reporting" tabindex="-1">Issue Reporting <a href="#issue-reporting" id="issue-reporting"></a> <a class="header-anchor" href="#issue-reporting" aria-label="Permalink to &quot;Issue Reporting &lt;a href=&quot;#issue-reporting&quot; id=&quot;issue-reporting&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>We&#39;re always trying to make our documentation, instructions, software, and user experience better. If you&#39;re having an issue with anything, please report it so that we can address it as soon as possible! Here&#39;s where to do that depending on what&#39;s wrong:</p><ul><li><strong>ArduSub Issues:</strong> For anything related to the ArduSub software that runs on the Pixhawk and controls the ROV, reports issues on the <a href="https://github.com/bluerobotics/ardusub/issues" target="_blank" rel="noreferrer">ArduSub Github Issues Page</a>. If you&#39;re unsure where your issue should be posted, you can report it here.</li><li><strong>QGroundControl Issues:</strong> For anything related to the QGroundControl software, joystick setup, video streaming, etc., please report an issue on the <a href="https://github.com/mavlink/qgroundcontrol/issues" target="_blank" rel="noreferrer">QGroundControl Github Issues Page</a>.</li><li><strong>Documentation:</strong> For anything related to the documentation and instructions here, please report an issue on the <a href="https://github.com/bluerobotics/ardusub-gitbook/issues" target="_blank" rel="noreferrer">ArduSub Documentation Github Issues Page</a>.</li></ul>`,75)])])}const m=t(i,[["render",s]]);export{d as __pageData,m as default};
